class Solution:
    def sellingWood(self, m, n, prices):
        from functools import lru_cache
        price = {}
        for h, w, p in prices:
            price[(h, w)] = p
        import sys
        sys.setrecursionlimit(100000)
        @lru_cache(maxsize=None)
        def best(h, w):
            res = price.get((h, w), 0)
            for i in range(1, h):
                res = max(res, best(i, w) + best(h - i, w))
            for j in range(1, w):
                res = max(res, best(h, j) + best(h, w - j))
            return res
        return best(m, n)

