var sellingWood = function(m, n, prices) {
    const dp = Array.from({length: m + 1}, () => new Array(n + 1).fill(0));
    for (const [h, w, p] of prices) {
        if (p > dp[h][w]) dp[h][w] = p;
    }
    for (let h = 1; h <= m; h++) {
        for (let w = 1; w <= n; w++) {
            let best = dp[h][w];
            for (let i = 1; i <= Math.floor(h / 2); i++) {
                const cand = dp[i][w] + dp[h - i][w];
                if (cand > best) best = cand;
            }
            for (let j = 1; j <= Math.floor(w / 2); j++) {
                const cand = dp[h][j] + dp[h][w - j];
                if (cand > best) best = cand;
            }
            dp[h][w] = best;
        }
    }
    return dp[m][n];
};
